interface User {
  id: number;
  name: string;
  email: string;
}

const user: User = {
  id: 1,
  name: "Alice",
  email: "alice@example.com",
};

console.log(user.name);
console.log(user.email);

interface Product {
  id: number;
  name: string;
  description?: string;
  price: number;
}

const shirt: Product = { id: 1, name: "T-Shirt", price: 19.99 };
const mug: Product = { id: 2, name: "Mug", description: "16oz ceramic", price: 12.99 };

console.log(shirt.description ?? "no description");
console.log(mug.description ?? "no description");

interface Greeter {
  greet(name: string): string;
  farewell(name: string): string;
}

const formal: Greeter = {
  greet: (name) => `Good morning, ${name}.`,
  farewell: (name) => `Goodbye, ${name}.`,
};

console.log(formal.greet("Dr. Smith"));
console.log(formal.farewell("Dr. Smith"));

interface Shape {
  color: string;
  area(): number;
}

interface Circle extends Shape {
  radius: number;
}

const circle: Circle = {
  color: "red",
  radius: 5,
  area() {
    return Math.PI * this.radius * this.radius;
  },
};

console.log(circle.color);
console.log(circle.area().toFixed(2));
